#include <iostream>
#include <algorithm>
using namespace std;
int a[1000005] = {0};
int main()
{
    int b,n,count=1;
    cin>>n>>b;
    for(int i=2;i<=n;i++)
    {
        if(a[i] == 0)
        {
            for(int j=1;i*j<=n;j++)
            {
                a[i*j]=i;
            }
        }
    }
    for (int i = 1; i <= n;i++) {
        if ((a[i] <= b && a[i] > 0) ) 
        {
            count++;
        }
    }

    cout<<count;
    return 0;
}
